# Handle negative tenure (future signup dates) - set to 0
df_clean.loc[df_clean['tenure_days'] < 0, 'tenure_days'] = 0

# Create segmentation features
# 1. Spending tier
df_clean['spending_tier'] = pd.cut(df_clean['monthly_spend'], 
                                     bins=[-0.01, 0.01, 20, 60, 1000],
                                     labels=['None', 'Low', 'Medium', 'High'])

# 2. Tenure tier (in months for easier interpretation)
df_clean['tenure_months'] = df_clean['tenure_days'] / 30
df_clean['tenure_tier'] = pd.cut(df_clean['tenure_months'], 
                                  bins=[-1, 3, 12, 24, 100],
                                  labels=['New', 'Growing', 'Established', 'Veteran'])

# 3. Create customer segments based on multiple factors
def assign_segment(row):
    """
    Segment customers based on spending, tenure, activity, and plan tier
    """
    spending = row['monthly_spend']
    tenure_m = row['tenure_months']
    active = row['is_active']
    plan = row['plan_tier']

    # High-value segments
    if spending >= 100:
        if active:
            return 'Champions'
        else:
            return 'At-Risk High-Value'

    # Enterprise customers
    if plan == 'enterprise':
        if active:
            return 'Enterprise Active'
        else:
            return 'Enterprise Churned'

    # Premium customers
    if plan == 'premium':
        if active and spending >= 40:
            return 'Premium Engaged'
        elif active:
            return 'Premium Low-Spend'
        else:
            return 'Premium Churned'

    # Basic plan customers
    if plan == 'basic':
        if active and tenure_m >= 12:
            return 'Loyal Basic'
        elif active and tenure_m < 12:
            return 'New Basic'
        else:
            return 'Basic Churned'

    # Free plan customers
    if plan == 'free':
        if active and tenure_m >= 6:
            return 'Free Long-term'
        elif active and tenure_m < 6:
            return 'Free New'
        elif spending > 0:
            return 'Free Paying Churned'
        else:
            return 'Free Inactive'

    return 'Other'

df_clean['segment'] = df_clean.apply(assign_segment, axis=1)

print("Customer Segments Distribution:")
print(df_clean['segment'].value_counts().sort_values(ascending=False))
print("\nSegment by Active Status:")
print(pd.crosstab(df_clean['segment'], df_clean['is_active']))
